use clap::{Parser, Subcommand};

/// My CLI application for managing tasks
#[derive(Parser)]
#[command(version, about)]
struct Cli {
    /// Enable verbose output
    #[arg(short, long)]
    verbose: bool,

    /// Config file path
    #[arg(short, long, default_value = "config.toml")]
    config: String,

    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// List all items
    List {
        #[arg(long, default_value_t = 10)]
        limit: usize,
    },
    /// Add a new item
    Add { name: String },
}

fn main() {
    let cli = Cli::parse();
    match cli.command {
        Commands::List { limit } => list_items(limit),
        Commands::Add { name } => add_item(&name),
    }
}

