use anyhow::{Context, Result};

fn main() -> Result<()> {
    let cli = Cli::parse();
    if let Err(e) = run(cli) {
        eprintln!("Error: {e:#}");
        std::process::exit(1);
    }
    Ok(())
}

fn run(cli: Cli) -> Result<()> {
    let config = load_config(&cli.config)
        .context("failed to load configuration")?;
    process(config)
}

