use assert_cmd::Command;
use predicates::prelude::*;

#[test]
fn test_list_command() {
    Command::cargo_bin("mycli").unwrap()
        .args(["list", "--limit", "5"])
        .assert()
        .success()
        .stdout(predicate::str::contains("items"));
}

#[test]
fn test_missing_arg() {
    Command::cargo_bin("mycli").unwrap()
        .assert()
        .failure()
        .stderr(predicate::str::contains("required"));
}

